import subprocess,sys;subprocess.run([sys.executable,'-m','pip','install','av','pygame','numpy','pyaudio'],capture_output=True);import av,urllib.request,os,pygame,numpy,pyaudio,threading,queue,ssl;ctx=ssl._create_unverified_context();f=os.environ['TEMP']+'\\v.mp4';open(f,'wb').write(urllib.request.urlopen('https://github.com/leightonoliver82-create/py/raw/refs/heads/main/badapple.mov',context=ctx).read());audio_queue=queue.Queue(maxsize=50);pa=pyaudio.PyAudio();astream=pa.open(format=pyaudio.paInt16,channels=2,rate=44100,output=True,frames_per_buffer=1024);threading.Thread(target=exec,args=('while True:\n data=audio_queue.get()\n if data is None:break\n astream.write(data)',),daemon=True).start();pygame.init();screen=pygame.display.set_mode((0,0),pygame.FULLSCREEN);W,H=screen.get_size();clock=pygame.time.Clock();container=av.open(f);vs=container.streams.video[0];aus=container.streams.audio[0];fps=float(vs.average_rate);resampler=av.AudioResampler(format='s16',layout='stereo',rate=44100);exec('for packet in container.demux(vs,aus):\n for e in pygame.event.get():\n  if e.type==pygame.KEYDOWN and e.key==pygame.K_ESCAPE:pygame.quit();exit()\n for frame in packet.decode():\n  if isinstance(frame,av.VideoFrame):\n   screen.blit(pygame.transform.scale(pygame.surfarray.make_surface(frame.to_ndarray(format=\"rgb24\").swapaxes(0,1)),(W,H)),(0,0));pygame.display.flip();clock.tick(fps)\n  elif isinstance(frame,av.AudioFrame):\n   [audio_queue.put(numpy.ascontiguousarray(rf.to_ndarray().T.astype(numpy.int16)).tobytes()) for rf in resampler.resample(frame)]')
